    public Solution() {
        queue = new Queue<int>();
    }

    public void implementStackUsingQueues(int data) {
        queue.Enqueue(data);
    }

    public int Pop() {
        if (queue.Count == 0) throw new InvalidOperationException("Stack is empty");

        int size = queue.Count;
        for (int i = 0; i < size - 1; i++) {
            queue.Enqueue(queue.Dequeue());
        }
        return queue.Dequeue();
    }

    public int Top() {
        if (queue.Count == 0) throw new InvalidOperationException("Stack is empty");

        int size = queue.Count;
        for (int i = 0; i < size - 1; i++) {
            queue.Enqueue(queue.Dequeue());
        }
        int topElement = queue.Dequeue();
        queue.Enqueue(topElement);
        return topElement;
    }

    public bool IsEmpty() {
        return queue.Count == 0;
    }
}
